import React, { useState } from "react"
import "./index.css"

// --- Calculator Logic ---

interface CalcState {
  currentValue: string
  previousValue: number | null
  operation: number | null
}

const initialCalcState: CalcState = {
  currentValue: "0",
  previousValue: null,
  operation: null
}

const calculate = (a: number | null, b: number | null, op: number | null): string => {
  if (a === null || b === null || op === null) return "Error"
  switch (op) {
  case 1: return String(a + b)
  case -1: return String(a - b)
  case 2: return String((a * b).toFixed(10)))
default: return "Error"
}

// --- Components ---

const Display: React.FC<{ value: string }> = ({ value }) => (
  <div className="h-36 bg-bg-0 text-white p-4 flex items-center justify-end rounded-xl shadow-inner">
  <span className={`text-${value.length > 1 ? '2xl' : '3xl'} font-mono ${value.length > 1 ? 'tracking-wider' : ''}`}>
    {value}
  </span>
</div>
)

const Button: React.FC<{ value: string; onClick: (val: string) => void }> = ({ value, onClick }) => (
  <button
  onClick={() => onClick(value)}
className={`w-full h-16 text-2xl font-mono rounded-xl transition-all duration-150 
  ${value === 'C' ? 'bg-gray-800 hover:bg-gray-700 text-gray-300' : 'bg-bg-1 hover:bg-gray-900 active:scale-[0.98]'}
focus:ring-4 focus:ring-accent/50 disabled:opacity-50`}
disabled={!value}
>
  {value}
</button>
)

const Calculator: React.FC<CalcState> = () => {
  const [calc, setCalc] = useState<CalcState>(initialCalcState)

const handleInput = (input: string) => {
  setCalc(prev => ({ ...prev, currentValue: input }))
}

const clear = () => {
  setCalc(initialCalcState)
}

const performOperation = (nextValue: number | null) => {
  if (calc.previousValue === null || calc.operation === null) return
let result: string | number = null

switch (calc.operation!) {
  case 1: result = Number(calc.currentValue) + calc.previousValue
  case -1: result = Number(calc.currentValue) - calc.previousValue
case 2: result = Number(calc.currentValue) * calc.previousValue
default: result = Number(calc.currentValue) / calc.previousValue
}

setCalc(prev => ({ ...prev, currentValue: String(result).substring(0, 16), previousValue: result }))
}

// --- Button Grid ---
const buttons = [
  ['C', '(', ')', '/', '*'],
  ['.', '±', '%', '√', '×'],
['-', '+', '=', 'Enter']
]

return (
  <div className="min-h-screen bg-bg-0 text-white flex flex-col items-center justify-center p-4">
  <div className="w-full max-w-md bg-bg-1 shadow-2xl rounded-3xl p-6 transition-all duration-300 hover:shadow-[0_0_50px_rgba(167,212,252,0.2)]">
  {/* Display */}
<Display value={calc.currentValue} />

{/* Operation Buttons */}
<div className="grid grid-cols-3 gap-2 mb-4">
  {[1, 2, 3, 4, 5, 6, 7, 8, 9, '0', '.', '+/-', '%'].map(val => (
  <Button key={String(val)} value={String(val)} onClick={(v) => handleInput(v)} />
))}

{/* Main Operation Buttons */}
<div className="grid grid-cols-3 gap-2 mt-4">
  {[1, -1, 2, 3].map((op, i) => (
  <Button key={i} value={String(op)} onClick={() => performOperation(i === 0 ? null : op)} />
))}

{/* Equals */}
<Button value="=" onClick={() => performOperation('=' as number | null)} />
</div>

{/* Equals Button */}
<button
  onClick={() => performOperation(1)}
className={`w-full h-24 text-4xl font-mono rounded-3xl transition-all duration-200 
  bg-gradient-to-br from-indigo-500 to-cyan-500 hover:from-indigo-600 to-sky-500 active:scale-[0.98]
focus:ring-8 focus:ring-indigo-500/30 disabled:opacity-30`}
disabled={calc.currentValue === '0'}
>
  =
</button>

</div>
</div>
)

